{"construct":"workflow_def","description":"a durable data pipeline with exponential backoff","name":"retry_pipeline","vox_snippet":"@workflow fn retry_pipeline(job: Job) to JobResult:
    let mut attempts = 0
    loop:
        let res = vox_run_job(job)
        if res.success:
            ret res
        attempts += 1
        if attempts > 3:
            ret JobResult { success: false, error: "max retries" }
        vox_sleep(Duration::from_mins(2 ^ attempts))
"}

